patch:
--- a/decoder.v
+++ b/decoder.v
@@ -9,14 +9,14 @@ module decoder_3to8(
 module processor;
   reg [2:0] select;
   wire [7:0] output_lines;

   decoder_3to8 dec (
     .sel(select),
     .out(output_lines),
-    .enable(1'b1),
-    .reset(1'b0)
+    .enable(1'b1)
   );
 endmodule

before_code:
module decoder_3to8(
  input [2:0] sel,
  input enable,
  output [7:0] out
);
  assign out = enable ? (8'b1 << sel) : 8'b0;
endmodule

module processor;
  reg [2:0] select;
  wire [7:0] output_lines;

  decoder_3to8 dec (
    .sel(select),
    .out(output_lines),
    .enable(1'b1),
    .reset(1'b0)
  );
endmodule

after_code:
module decoder_3to8(
  input [2:0] sel,
  input enable,
  output [7:0] out
);
  assign out = enable ? (8'b1 << sel) : 8'b0;
endmodule

module processor;
  reg [2:0] select;
  wire [7:0] output_lines;

  decoder_3to8 dec (
    .sel(select),
    .out(output_lines),
    .enable(1'b1)
  );
endmodule
